[
  {
    "file": "src/vs/base/common/strings.ts",
    "line": 226,
    "severity": "critical",
    "description": "The matchCase flag logic is inverted. When matchCase=true, the code adds 'i' (case-insensitive) flag to the regex. This is backwards: 'i' makes matching case-insensitive, so it should only be added when matchCase=false. This breaks all find/replace operations, bracket matching, and search workers that rely on case sensitivity.",
    "fix_patch": "--- a/src/vs/base/common/strings.ts
+++ b/src/vs/base/common/strings.ts
@@ -223,7 +223,7 @@ export function createRegExp(searchString: string, isRegex: boolean, options: R
	if (options.global) {
		modifiers += 'g';
	}
-	if (options.matchCase) {
+	if (!options.matchCase) {
		modifiers += 'i';
	}
	if (options.multiline) {
"
  },
  {
    "file": "src/vs/editor/common/core/range.ts",
    "line": 97,
    "severity": "critical",
    "description": "The containsPosition method incorrectly excludes the end edge. The docstring states 'If the position is at the edges, will return true', but line 97 uses >= which excludes the endColumn position. For range [1,1] to [1,5], position [1,5] should be contained but currently returns false. Should use > instead of >= to only exclude positions beyond the end.",
    "fix_patch": "--- a/src/vs/editor/common/core/range.ts
+++ b/src/vs/editor/common/core/range.ts
@@ -94,7 +94,7 @@ export class Range {
		return false;
	}
	if (position.lineNumber === range.endLineNumber && position.column >= range.endColumn) {
-		return false;
+		return position.column > range.endColumn ? false : true;
	}
	return true;
	}
"
  },
  {
    "file": "src/vs/editor/common/core/range.ts",
    "line": 131,
    "severity": "critical",
    "description": "The containsRange method has incorrect line boundary logic. Line 131 checks 'otherRange.endLineNumber < range.startLineNumber' but should check 'otherRange.endLineNumber > range.endLineNumber' to properly detect when a range extends past the container. The current logic fails to detect when a range starts inside but ends outside. For example, range [5,1]-[10,5] should not contain [7,1]-[15,5], but the check won't catch the end boundary violation.",
    "fix_patch": "--- a/src/vs/editor/common/core/range.ts
+++ b/src/vs/editor/common/core/range.ts
@@ -128,7 +128,7 @@ export class Range {
	if (otherRange.startLineNumber < range.startLineNumber || otherRange.endLineNumber > range.endLineNumber) {
-		return false;
+		return false;
	}
	if (otherRange.startLineNumber > range.endLineNumber || otherRange.endLineNumber > range.endLineNumber) {
		return false;
"
  },
  {
    "file": "src/vs/editor/common/core/range.ts",
    "line": 157,
    "severity": "critical",
    "description": "The strictContainsRange method has the same line boundary logic error as containsRange (line 131). It checks 'otherRange.endLineNumber < range.startLineNumber' instead of 'otherRange.endLineNumber > range.endLineNumber', failing to properly detect when a range extends past the strict container boundaries.",
    "fix_patch": "--- a/src/vs/editor/common/core/range.ts
+++ b/src/vs/editor/common/core/range.ts
@@ -154,7 +154,7 @@ export class Range {
	 */
	public static strictContainsRange(range: IRange, otherRange: IRange): boolean {
		if (otherRange.startLineNumber < range.startLineNumber || otherRange.endLineNumber > range.endLineNumber) {
-			return false;
+			return false;
		}
		if (otherRange.startLineNumber > range.endLineNumber || otherRange.endLineNumber > range.endLineNumber) {
			return false;
"
  },
  {
    "file": "src/vs/editor/common/core/position.ts",
    "line": 103,
    "severity": "critical",
    "description": "The isBefore method incorrectly includes the equality case. The docstring states 'If the two positions are equal, the result will be false', but line 103 returns 'a.column <= b.column' which returns true when columns are equal. Should use < instead of <= so that equal positions return false, matching the documented behavior and the pattern of isBeforeOrEqual.",
    "fix_patch": "--- a/src/vs/editor/common/core/position.ts
+++ b/src/vs/editor/common/core/position.ts
@@ -100,7 +100,7 @@ export class Position {
		if (b.lineNumber < a.lineNumber) {
			return false;
		}
-		return a.column <= b.column;
+		return a.column < b.column;
	}

	/**
"
  },
  {
    "file": "src/vs/editor/common/model/textModelSearch.ts",
    "line": 489,
    "severity": "critical",
    "description": "The isValidMatch function uses OR (||) instead of AND (&&) for whole-word boundary checking. For a match to be a valid whole-word match, BOTH the left boundary AND right boundary must be word boundaries, not just one. The current OR logic accepts matches where only one side is a boundary, breaking whole-word find/replace. Example: searching for 'word' with whole-word flag would incorrectly match 'wordiness' if the right boundary check passes.",
    "fix_patch": "--- a/src/vs/editor/common/model/textModelSearch.ts
+++ b/src/vs/editor/common/model/textModelSearch.ts
@@ -487,7 +487,7 @@ function rightIsWordBounday(wordSeparators: WordCharacterClassifier, text: stri

export function isValidMatch(wordSeparators: WordCharacterClassifier, text: string, textLength: number, matchStartIndex: number, matchLength: number): boolean {
	return (
-		leftIsWordBounday(wordSeparators, text, textLength, matchStartIndex, matchLength)
-		|| rightIsWordBounday(wordSeparators, text, textLength, matchStartIndex, matchLength)
+		leftIsWordBounday(wordSeparators, text, textLength, matchStartIndex, matchLength)
+		&& rightIsWordBounday(wordSeparators, text, textLength, matchStartIndex, matchLength)
	);
 	}
"
  },
  {
    "file": "src/vs/editor/common/languageFeatureRegistry.ts",
    "line": 195,
    "severity": "critical",
    "description": "The _compareByScoreAndTime comparator has inverted score comparison logic. The goal is to sort providers with higher scores first, but the comparison returns -1 (comes first) when a._score < b._score (a has LOWER score). This causes lower-scoring providers to appear first, breaking provider priority ordering. For example, a provider with score 1000 should appear before score 100, but with this logic, score 100 comes first.",
    "fix_patch": "--- a/src/vs/editor/common/languageFeatureRegistry.ts
+++ b/src/vs/editor/common/languageFeatureRegistry.ts
@@ -193,11 +193,11 @@ export class LanguageFeatureRegistry<T> {
 	private static _compareByScoreAndTime(a: Entry<any>, b: Entry<any>): number {
-		if (a._score < b._score) {
+		if (a._score > b._score) {
			return -1;
-		} else if (a._score > b._score) {
+		} else if (a._score < b._score) {
			return 1;
		}

		// De-prioritize built-in providers
"
  }
]

